1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	}
14	
15	interface QuoteStep {
16	  op: "quote";
17	  items: Item[];
18	}
19	
20	interface Scenario {
21	  customer: { yearsWithMHPCO: number };
22	  steps: QuoteStep[];
23	}
24	
25	const itemPremium = (item: Item): number => {
26	  const base = BASE_PREMIUM_BY_TYPE[item.type];
27	  return Math.ceil(base + base * FIRST_INSURANCE_SURCHARGE);
28	};
29	
30	const sumItemPremiums = (items: Item[]): number =>
31	  items.reduce((sum, item) => sum + itemPremium(item), 0);
32	
33	const quoteStep = (step: QuoteStep) => ({
34	  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
35	});
36	
37	export const processScenario = (scenario: Scenario): unknown => {
38	  const results = scenario.steps.map(quoteStep);
39	  return { results };
40	};
